package com.evolua.auth.interfaces.rest; import com.evolua.auth.application.AuthService; import com.evolua.auth.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import jakarta.validation.constraints.Email; import jakarta.validation.constraints.NotBlank; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping public class AuthController { private final AuthService authService; private final CurrentUserProvider currentUserProvider; public AuthController(AuthService authService, CurrentUserProvider currentUserProvider) { this.authService = authService; this.currentUserProvider = currentUserProvider; } @PostMapping("/v1/public/auth/register") @Operation(summary = "Register user") public ResponseEntity<ApiResponse<AuthUserResponse>> register(@Valid @RequestBody RegisterRequest request) { var user = authService.register(request.email(), request.password()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", new AuthUserResponse(user.userId(), user.email(), user.roles()))); } @PostMapping("/v1/public/auth/login") @Operation(summary = "Login user") public ResponseEntity<ApiResponse<TokenResponse>> login(@Valid @RequestBody LoginRequest request) { var tokens = authService.login(request.email(), request.password()); return ResponseEntity.ok(ApiResponse.success(200, "Logged in", new TokenResponse(tokens.accessToken(), tokens.refreshToken()))); } @PostMapping("/v1/public/auth/refresh") @Operation(summary = "Refresh tokens") public ResponseEntity<ApiResponse<TokenResponse>> refresh(@Valid @RequestBody RefreshRequest request) { var tokens = authService.refresh(request.refreshToken()); return ResponseEntity.ok(ApiResponse.success(200, "Refreshed", new TokenResponse(tokens.accessToken(), tokens.refreshToken()))); } @GetMapping("/v1/auth/me") @Operation(summary = "Current account") public ResponseEntity<ApiResponse<AuthUserResponse>> me() { var user = authService.me(currentUserProvider.getCurrentUser().userId()); return ResponseEntity.ok(ApiResponse.success(200, "Current user", new AuthUserResponse(user.userId(), user.email(), user.roles()))); } public record RegisterRequest(@Email String email, @NotBlank String password) { } public record LoginRequest(@Email String email, @NotBlank String password) { } public record RefreshRequest(@NotBlank String refreshToken) { } public record TokenResponse(String accessToken, String refreshToken) { } public record AuthUserResponse(String userId, String email, List<String> roles) { } }
